/* eslint-disable class-methods-use-this */
import { FaceMesh } from '@zappar/zappar';
import * as THREE from 'three';
/**
 * Loader for adaptive face mesh data.
 * @see https://docs.zap.works/universal-ar/web-libraries/threejs/face-tracking/
 */
export class FaceMeshLoader extends THREE.Loader {
    // Implementation that handles both signatures
    load(urlOrOptions, onLoadCallback, onProgressCallback, onErrorCallback) {
        // Check if we're using the new required pattern (url is string and onLoad is required)
        const isNewPattern = typeof urlOrOptions === 'string' && typeof onLoadCallback === 'function' && (!onProgressCallback || onProgressCallback.length !== 0);
        if (isNewPattern) {
            // Handle as new-style (void return)
            const url = urlOrOptions;
            const onLoad = onLoadCallback;
            const trk = new FaceMesh();
            const itemFilename = `__zappar_threejs_face_mesh_${url}`;
            this.manager.itemStart(itemFilename);
            trk
                .load(url)
                .then(() => {
                onLoad(trk);
                this.manager.itemEnd(itemFilename);
            })
                .catch(err => {
                if (onErrorCallback)
                    onErrorCallback(err);
                this.manager.itemError(itemFilename);
                this.manager.itemEnd(itemFilename);
            });
            return;
        }
        else {
            // Original implementation (returns FaceMesh)
            const options = urlOrOptions;
            const onLoad = onLoadCallback;
            const onError = onErrorCallback;
            const trk = new FaceMesh();
            let p;
            const itemFilename = `__zappar_threejs_face_mesh_${JSON.stringify(options || 'default')}`;
            this.manager.itemStart(itemFilename);
            if (options) {
                if (typeof options === 'string')
                    p = trk.load(options);
                else if (options.customModel)
                    p = trk.load(options.customModel, options.fillMouth, options.fillEyeLeft, options.fillEyeRight, options.fillNeck);
                else
                    p = trk.loadDefaultFace(options.fillMouth, options.fillEyeLeft, options.fillEyeRight);
            }
            else {
                p = trk.loadDefaultFace();
            }
            p.then(() => {
                if (onLoad)
                    onLoad(trk);
                this.manager.itemEnd(itemFilename);
            }).catch(_ => {
                if (onError)
                    onError(_);
                this.manager.itemError(itemFilename);
                this.manager.itemEnd(itemFilename);
            });
            return trk;
        }
    }
    /**
     * Loads the default face mesh.
     * @param options - Defines if some face features should be filled with polygons.
     * @param onLoad - Callback which returns the FaceMesh once it's loaded.
     * @param onError - Callback which is called if there's an error loading the mesh.
     * @returns The FaceMesh.
     */
    loadFace(options, onLoad, onProgress, onError) {
        const trk = new FaceMesh();
        let p;
        const itemFilename = `__zappar_threejs_face_mesh_face_${JSON.stringify(options || 'default')}`;
        if (options) {
            if (options.customModel)
                p = trk.load(options.customModel, options.fillMouth, options.fillEyeLeft, options.fillEyeRight, options.fillNeck);
            else
                p = trk.loadDefaultFace(options.fillMouth, options.fillEyeLeft, options.fillEyeRight);
        }
        else {
            p = trk.loadDefaultFace();
        }
        p.then(() => {
            if (onLoad)
                onLoad(trk);
            this.manager.itemEnd(itemFilename);
        }).catch(_ => {
            if (onError)
                onError(_);
            this.manager.itemError(itemFilename);
            this.manager.itemEnd(itemFilename);
        });
        return trk;
    }
    /**
     * Loads the full head simplified mesh which covers the whole of the user's head, including some neck.
     * It's ideal for drawing into the depth buffer in order to mask out the back of 3D models placed on the user's head.
     * @param options - Defines if some face features should be filled with polygons.
     * @param onLoad - Callback which returns the FaceMesh once it's loaded.
     * @param onError - Callback which is called if there's an error loading the mesh.
     * @returns The FaceMesh.
     */
    loadFullHeadSimplified(options, onLoad, onProgress, onError) {
        const trk = new FaceMesh();
        let p;
        const itemFilename = `__zappar_threejs_face_mesh_full_head_${JSON.stringify(options || 'default')}`;
        if (options) {
            if (options.customModel)
                p = trk.load(options.customModel, options.fillMouth, options.fillEyeLeft, options.fillEyeRight, options.fillNeck);
            else
                p = trk.loadDefaultFullHeadSimplified(options.fillMouth, options.fillEyeLeft, options.fillEyeRight, options.fillNeck);
        }
        else {
            p = trk.loadDefaultFullHeadSimplified();
        }
        p.then(() => {
            if (onLoad)
                onLoad(trk);
            this.manager.itemEnd(itemFilename);
        }).catch(_ => {
            if (onError)
                onError(_);
            this.manager.itemError(itemFilename);
            this.manager.itemEnd(itemFilename);
        });
        return trk;
    }
    /**
     * @ignore
     */
    parse() { }
}
